// CustomerService.java - Refactorizado con DTOs
@Service
public class CustomerService {

    @Autowired
    private CustomerRepository customerRepository;

    @Autowired
    private CustomerMapper customerMapper;  // Inyectar mapper

    public List<CustomerResponse> findAll() {
        List<Customer> customers = customerRepository.findAll();
        return customerMapper.toResponseList(customers);
    }

    public CustomerResponse findById(Long id) {
        Customer customer = customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));
        return customerMapper.toResponse(customer);
    }

    public CustomerResponse create(CustomerRequest request) {
        // Validar datos de request
        validateCustomerRequest(request);

        // Convertir Request a Entity
        Customer customer = customerMapper.toEntity(request);

        // Guardar en BD
        Customer saved = customerRepository.save(customer);

        // Convertir Entity a Response
        return customerMapper.toResponse(saved);
    }

    public CustomerResponse update(Long id, CustomerRequest request) {
        // Buscar customer existente
        Customer existing = customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));

        // Actualizar campos desde request
        customerMapper.updateEntityFromRequest(request, existing);

        // Guardar cambios
        Customer updated = customerRepository.save(existing);

        // Retornar response
        return customerMapper.toResponse(updated);
    }

    public void delete(Long id) {
        Customer customer = customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));
        customerRepository.delete(customer);
    }

    private void validateCustomerRequest(CustomerRequest request) {
        if (request.getName() == null || request.getName().isEmpty()) {
            throw new IllegalArgumentException("Name is required");
        }
        // ... más validaciones
    }
}

// CustomerRestController.java - Refactorizado
@RestController
@RequestMapping("/api/v1/customer")
@Tag(name = "Customer", description = "API de gestión de clientes")
public class CustomerRestController {

    @Autowired
    private CustomerService customerService;

    @GetMapping
    public ResponseEntity<List<CustomerResponse>> findAll() {
        return ResponseEntity.ok(customerService.findAll());
    }

    @GetMapping("/{id}")
    public ResponseEntity<CustomerResponse> findById(@PathVariable Long id) {
        return ResponseEntity.ok(customerService.findById(id));
    }

    @PostMapping
    public ResponseEntity<CustomerResponse> create(
            @RequestBody CustomerRequest request) {
        CustomerResponse created = customerService.create(request);
        return ResponseEntity.status(HttpStatus.CREATED).body(created);
    }

    @PutMapping("/{id}")
    public ResponseEntity<CustomerResponse> update(
            @PathVariable Long id,
            @RequestBody CustomerRequest request) {
        return ResponseEntity.ok(customerService.update(id, request));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable Long id) {
        customerService.delete(id);
        return ResponseEntity.noContent().build();
    }
}
